import React, { useState, useEffect } from 'react';
import { createBooking, getAvailableDates } from '../../services/ApiService';
import './BookingForm.css';

export default function BookingForm() {
  const [email, setEmail] = useState('');
  const [date, setDate] = useState('');
  const [message, setMessage] = useState('');
  const [availableDates, setAvailableDates] = useState([]);

  // Загружаем доступные даты при монтировании компонента
  useEffect(() => {
    const fetchDates = async () => {
      const dates = await getAvailableDates();
      setAvailableDates(dates);
    };
    fetchDates();
  }, []);

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const res = await createBooking(date, email);
      if (res.error) setMessage(res.error);
      else {
        setMessage('Бронь успешно создана!');
        // Обновляем список доступных дат после брони
        const dates = await getAvailableDates();
        setAvailableDates(dates);
        setDate(''); // очищаем выбранную дату
        setEmail(''); // очищаем email
      }
    } catch (err) {
      setMessage('Ошибка при создании брони');
    }
  };

  return (
    <form className="booking-form" onSubmit={handleSubmit}>
      <h2>Забронировать комнату</h2>
      <input
        type="email"
        placeholder="Ваш Email"
        value={email}
        onChange={(e) => setEmail(e.target.value)}
        required
      />

      {/* Выбор даты через select */}
      <select
        value={date}
        onChange={(e) => setDate(e.target.value)}
        required
      >
        <option value="">Выберите дату</option>
        {availableDates.map(d => (
          <option key={d} value={d}>{d}</option>
        ))}
      </select>

      <button type="submit">Забронировать</button>
      <p>{message}</p>
    </form>
  );
}
